{
  "mode": "method",
  "tests": [
    {
      "name": "valid_user_login",
      "input": {
        "username": "testuser",
        "password": "securepassword"
      },
      "output": {
        "status": "success",
        "token": "valid_jwt_token"
      },
      "notes": "Tests successful login with valid credentials."
    },
    {
      "name": "invalid_user_login",
      "input": {
        "username": "testuser",
        "password": "wrongpassword"
      },
      "output": {
        "status": "error",
        "message": "Invalid credentials"
      },
      "notes": "Tests login failure with invalid credentials."
    },
    {
      "name": "user_not_found",
      "input": {
        "username": "nonexistentuser",
        "password": "anyPassword"
      },
      "output": {
        "status": "error",
        "message": "User not found"
      },
      "notes": "Tests login attempt for a user that does not exist."
    },
    {
      "name": "role_assignment",
      "input": {
        "userId": "12345",
        "role": "admin"
      },
      "output": {
        "status": "success",
        "message": "Role assigned successfully"
      },
      "notes": "Tests assigning a role to a user."
    },
    {
      "name": "duplicate_role_assignment",
      "input": {
        "userId": "12345",
        "role": "admin"
      },
      "output": {
        "status": "error",
        "message": "Role already assigned"
      },
      "notes": "Tests attempting to assign a role that is already assigned."
    },
    {
      "name": "e2e_test_user_creation",
      "input": {
        "username": "newuser",
        "password": "newpassword"
      },
      "output": {
        "status": "success",
        "message": "User created successfully"
      },
      "notes": "Tests end-to-end user creation process."
    },
    {
      "name": "e2e_test_user_deletion",
      "input": {
        "userId": "12345"
      },
      "output": {
        "status": "success",
        "message": "User deleted successfully"
      },
      "notes": "Tests end-to-end user deletion process."
    },
    {
      "name": "e2e_test_role_retrieval",
      "input": {
        "userId": "12345"
      },
      "output": {
        "status": "success",
        "roles": ["admin", "user"]
      },
      "notes": "Tests retrieval of roles for a user."
    }
  ],
  "assumptions": "Database is seeded with test data before running tests.",
  "notes": "Ensure all tests run against a real database instance."
}
